mapper.select:
SELECT
a.id id,
a.label_name labelName,
a.change_type changeType,
a.before_change beforeChange,
a.after_change afterChange,
a.last_operator updaterName,
a.created_time updatedTime
FROM site_user_label_config_record a

    a.site_code = #{siteCode}

        AND a.created_time  >=  #{vo.updateTimeStart}


        AND a.created_time  <=  #{vo.updateTimeEnd}


        AND a.change_type = #{vo.changeType}


        AND a.last_operator like CONCAT('%',#{vo.updaterName}, '%')




        ORDER BY ${vo.orderField} ${vo.orderType}


        ORDER BY a.created_time DESC

SELECT
count(1)
FROM site_user_label_config_record a

    and a.site_code = #{siteCode}

        AND a.created_time  >=  #{vo.updateTimeStart}


        AND a.created_time  <=  #{vo.updateTimeEnd}


        AND a.change_type = #{vo.changeType}


        AND a.last_operator = #{vo.updaterName}
